const DEFAULT_IMG = TEMPLATE_IMAGES[1];

// Fallback mock (API fails)
const mockRanking = {
  title: "My Ranking",
  subtitle: "My Ranking",
  tiers: [
    { label: "Tier S", items: [] },
    { label: "Tier A", items: [] },
    { label: "Tier B", items: [] },
    { label: "Tier C", items: [] },
    { label: "Tier D", items: [] },
    { label: "Tier E", items: [] },
    { label: "Tier F", items: [] },
  ],
};

const TIER_ORDER = ["S", "A", "B", "C", "D", "E", "F"];

function normalizeKey(value = "") {
  return value.trim().toLowerCase();
}

function getItemImage(item, apiData) {
  const itemName = normalizeKey(item.item_name);
  const templateId = apiData?.template_id;

  return (
    ITEM_IMAGES_BY_TEMPLATE[templateId]?.[itemName] ||
    TEMPLATE_IMAGES[templateId] ||
    DEFAULT_IMG
  );
}

// Converts backend response -> UI model page expects
function toUiRanking(apiData, template_name) {
  const buckets = new Map(TIER_ORDER.map((t) => [t, []]));

  for (const item of apiData.item_rankings || []) {
    const tier = (item.tier || "").toUpperCase();
    if (!buckets.has(tier)) continue;

    buckets.get(tier).push({
      id: String(item.item_id),
      name: item.item_name,
      img: getItemImage(item, apiData),
      tier: tier,
    });
  }

  return {
    title: template_name,
    subtitle: "My Ranking",
    tiers: TIER_ORDER.map((t) => ({
      label: `Tier ${t}`,
      items: buckets.get(t),
    })),
  };
}

function TierSection({ label, items }) {
  const letter = label.replace("Tier ", "");

  return (
    <section className="tierRow">
      <div className="tierLabel">{letter}</div>

      <div className="tierContent">
        <div className="tierGridCompact">
          {items.map((item) => (
            <article key={item.id} className="itemCardCompact">
              <img
                className="thumb"
                src={item.img}
                alt={item.name}
                onError={(e) => {
                  e.currentTarget.src = DEFAULT_IMG;
                }}
              />
              <div className="text">
                <div className="name">{item.name}</div>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

export default function RankingPage() {
  const { rankingId } = useParams();
  const location = useLocation();
  const { template_name } = location.state;

  const [ranking, setRanking] = useState(mockRanking);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch(
          `https://metatier.turkmenkaan.xyz:8000/tier-list/${rankingId}`,
          {
            headers: {
              "Content-Type": "application/json",
              "ngrok-skip-browser-warning": "true",
            },
          }
        );

        if (!response.ok) {
          console.log(`HTTP error ${response.status}`);
          return;
        }

        const data = await response.json();
        setRanking(toUiRanking(data, template_name));
        console.log(data);
      } catch (err) {
        console.log(err.message);
      }
    };

    fetchData();
  }, [rankingId, template_name]);

  return (
    <div className="globalPage">
      <div className="container">
        <div className="top">
          <div>
            <h1 className="title">{ranking.title}</h1>
            <div className="subtitle">{ranking.subtitle}</div>
          </div>
        </div>

        <div className="tiers">
          {ranking.tiers.map((tier) => (
            <TierSection
              key={tier.label}
              label={tier.label}
              items={tier.items}
            />
          ))}
        </div>

        {rankingId ? (
          <div className="idChip">
            Rank Id: <span className="idChipValue">{rankingId}</span>
          </div>
        ) : null}
      </div>
    </div>
  );
}